import app.k9mail.legacy.account.AccountManager
import app.k9mail.legacy.preferences.SettingsChangePublisher
import com.fsck.k9.K9
import com.fsck.k9.Preferences

/**
 * Configures the unified inbox after an account has been added.
 */
class UnifiedInboxConfigurator(
    private val accountManager: AccountManager,
    private val preferences: Preferences,
    private val settingsChangePublisher: SettingsChangePublisher,
) {
    fun configureUnifiedInbox() {
        // Only auto-enable unified inbox when a second account is added and the user hasn't explicitly
        // configured this setting yet.
        val finishedAccountsCount = accountManager.getAccounts().count { it.isFinishedSetup }
        if (finishedAccountsCount < 2) return

        // Respect existing settings (e.g., users who disabled unified inbox).
        if (preferences.storage.contains(SHOW_UNIFIED_INBOX_KEY)) return

        enableUnifiedInbox()
    }

    private fun enableUnifiedInbox() {
        if (K9.isShowUnifiedInbox) return

        K9.isShowUnifiedInbox = true

        // Persist synchronously so the setting isn't lost if the app is killed shortly after account setup.
        preferences.createStorageEditor()
            .putBoolean(SHOW_UNIFIED_INBOX_KEY, true)
            .commit()

        // Notify UI layers that are driven by the settings change broker.
        settingsChangePublisher.publish()
    }

    private companion object {
        const val SHOW_UNIFIED_INBOX_KEY = "showUnifiedInbox"
    }
}
"}

