import app.k9mail.legacy.account.Account
import app.k9mail.legacy.account.AccountManager
import app.k9mail.legacy.preferences.SettingsChangePublisher
import com.fsck.k9.K9
import com.fsck.k9.Preferences
import org.junit.After
import org.junit.Before
import org.junit.Test
import org.mockito.kotlin.doReturn
import org.mockito.kotlin.mock
import org.mockito.kotlin.never
import org.mockito.kotlin.verify

class UnifiedInboxConfiguratorTest {
    private val accountManager = mock<AccountManager>()
    private val preferences = mock<Preferences>()
    private val settingsChangePublisher = mock<SettingsChangePublisher>()

    private val storageEditor = mock<StorageEditor> {
        on { putBoolean("showUnifiedInbox", true) } doReturn it
        on { commit() } doReturn true
    }

    private val subject = UnifiedInboxConfigurator(
        accountManager = accountManager,
        preferences = preferences,
        settingsChangePublisher = settingsChangePublisher,
    )

    @Before
    fun setUp() {
        K9.isShowUnifiedInbox = false
        doReturn(storageEditor).`when`(preferences).createStorageEditor()
    }

    @After
    fun tearDown() {
        K9.isShowUnifiedInbox = false
    }

    @Test
    fun `enables unified inbox when second finished account is added and setting wasn't configured yet`() {
        val account1 = Account("uuid-1").apply { markSetupFinished() }
        val account2 = Account("uuid-2").apply { markSetupFinished() }

        doReturn(listOf(account1, account2)).`when`(accountManager).getAccounts()
        doReturn(Storage(emptyMap())).`when`(preferences).storage

        subject.configureUnifiedInbox()

        verify(storageEditor).putBoolean("showUnifiedInbox", true)
        verify(storageEditor).commit()
        verify(settingsChangePublisher).publish()
    }

